import math

def get_divisors(n):
    if n <= 0:
        raise ValueError("Input must be a positive integer.")
    divisors = set()
    for i in range(1, int(math.sqrt(n)) + 1):
        if n % i == 0:
            divisors.add(i)
            divisors.add(n // i)
    return sorted(list(divisors))
